interface ISkillItemProps {
    Source: string;
    Href: string;
}

function SkillItem(Prop: ISkillItemProps) {    
    const theme = useTheme()
    const isMobile = useMediaQuery(theme.breakpoints.down('md'))
    var size = ""        
    var variant = "" as "body2" | "h6"

    if (isMobile){
        size = "56px"        
        variant = "body2"        
    } else {
        size = "96px"        
        variant = "h6"        
    } 
    
    return(
        <a target="_blank" rel="noreferrer noopener" href={Prop.Href}>            
            <Avatar sx={{border: 1, borderColor: "secondary.main", width: size ,height: size, m: 1, p: 1, borderRadius: "15%"}} variant="square" src={Prop.Source} alt=""/>
        </a>
    )
}


