import {Box, Button, Paper, Stack, Typography, useMediaQuery, useTheme}  from '@mui/material'
import { Link } from 'react-scroll'
import React from 'react'

import logo from "../../assets/placeholder.png";
import "./Intro.css"
// END REGION

export interface IIntroProps { } 
export default function Intro (props: IIntroProps) {
    const [window_w, setWindow_w] = React.useState(window.innerWidth);
    const [window_h, setWindow_h] = React.useState(window.innerHeight);

    window.addEventListener("resize", () => {
        setWindow_w(window.innerWidth)
        setWindow_h(window.innerHeight)
    });
    
    return (
    <Paper>
        <Box className='introSection' id='introSection' >
            {<img id='displayImage' src={logo} width={window_w - 12} height={window_h} alt=''/>}
        </Box>
    </Paper>
    )
}