import {Avatar, IconButton, Box, Chip, Button, Paper, Skeleton, Stack, Typography, useMediaQuery, useTheme}  from '@mui/material'
import { Link } from 'react-scroll'
import React, { SyntheticEvent } from 'react'

import logo from '../../assets/placeholder.png'
import left_arrow from "../../assets/left_arrow.svg";
import right_arrow from "../../assets/right_arrow.svg";
import "./Projects.css"

// END REGION

export interface IProjectItemProps {
    title: string;    
    discription: string;    
    weblink?: string;
    image?: string;
    topics?: string[];
}

export function ProjectItem ({title, discription, weblink = '#projectSection', topics = [], image = ''}: IProjectItemProps) {    
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down("md")); 
    
    function Links(item_list: string[]) {
        const links: any[] = []
        if (item_list.length > 0) {
            for(let i = 0; i < item_list.length; i++){
                if (i === 4){
                    break
                } else {
                    const text = item_list[i]
                    links.push(<Chip 
                        clickable 
                        key={text} 
                        variant="outlined" 
                        label={text} 
                        sx={{textAlign:"justify", maxWidth:"96px", overflow: "hidden", textOverflow: "ellipsis"}} 
                    />)
                }
            }
        }
        if (item_list.length <= 0) {
            return <div/>
        } else {            
            return (
                <Stack sx={{pt: 2}} spacing={2} direction={'row'}>
                    {links}
                </Stack>
            )
        }
    }

    return (
        <Paper elevation={6} 
            sx={isMobile? 
                    ({maxHeight: '80vh', mt: 4, p: 1, display: 'flex', flexDirection: 'column'}): 
                    ({width:"80vw", maxWidth:"80vw", p: 1, display: 'flex', flexDirection: 'row'})
                }
            >            
            <Box sx={isMobile? 
                ({width:"80vw", minWidth:"80vw", maxWidth:"80vw", height:"80vw", maxHeight:"80vw", borderRadius: "8px", display:"flex"}):
                ({width:"40vw", minWidth:"40vw", maxWidth:"40vw", height:"40vw", maxHeight:"40vw", borderRadius: "8px", display:"flex"})
            }>               
                {!(image === '') ? (
                    <Paper variant="outlined" elevation={2} >
                        <a href={weblink}>
                            <img src={image} 
                                style={isMobile? 
                                    ({width:"80vw", minWidth:"80vw", maxWidth:"80vw", height:"80vw", maxHeight:"80vw", objectFit: 'contain'}):
                                    ({width:"40vw", minWidth:"40vw", maxWidth:"40vw", height:"40vw", maxHeight:"40vw", objectFit: 'contain'})
                            }/>
                        </a>
                    </Paper>
                ):(
                    <Skeleton animation="wave" variant="rectangular" sx={{width:"inherit", height:"inherit", borderRadius: "8px"}} />
                )}                                             
            </Box>  
            <Box sx={isMobile? ({m: 0}):({ml: 4})}>
                <a style={{textDecoration: "none"}} href={weblink}>
                    <Typography 
                        sx={{fontWeight: "bold", color: "secondary.main"}} 
                        align={'left'} variant={isMobile ? ('h4'):('h2')}
                    >
                        {title}
                    </Typography>
                </a>
                {isMobile? (<div/>):(Links(topics))}
                <Typography 
                    sx={{color: "text.primary", pt: 1, overflow: "hidden", textOverflow: "ellipsis", maxWidth: 'fit-content'}} 
                    paragraph={true} align="left" variant={isMobile ? ('body2'):('h6')}
                >
                    {discription}
                </Typography>
            </Box>
        </Paper>
    );
}


const ProjectItemMap: IProjectItemProps[] = [
    {        
        title: 'Apollo',    
        discription: 'Apollo is a Open-Source music player for playback and organization of audio files on Microsoft Windows, built using Python.',   
        topics: ["audio-files", "apollo", "playback", "music", "metadata", "dsp", "signal-proce"],
        weblink: 'https://github.com/OmmarShaikh01/Apollo',
        image: 'https://raw.githubusercontent.com/OmmarShaikh01/Apollo/main/examples/MAINWINDOW.png'     
    }, 
    {        
        title: 'wordclock-rpi',    
        discription: 'Raspberry Pi word clock code written in python',        
        weblink: 'https://github.com/OmmarShaikh01/wordclock-rpi'     
    }, 
    {        
        title: 'JMessenger',    
        discription: 'Open source chat application for android',       
        topics: ['kotlin-android', 'firebase', 'chat-application', 'firebase-auth', 'firebase-database'],
        weblink: 'https://github.com/OmmarShaikh01/JMessenger',
        image: 'https://raw.githubusercontent.com/OmmarShaikh01/JMessenger/main/UI_images/J1.png'      
    } 
]


var itemIndex = 0
export interface IProjectsProps { } 
export default function Projects (props: IProjectsProps) {
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down("md"));    
    const [ProjectItemLoaded, setProjectItemLoaded] = React.useState(getProjectItem())

    function getProjectItem() {
        if (ProjectItemMap.length === 0) {
            return (
                <Box 
                sx={isMobile? 
                        ({maxHeight: '80vh', mt: 4, p: 1, display: 'flex', flexDirection: 'column'}): 
                        ({width:"80vw", maxWidth:"80vw", p: 1, display: 'flex', flexDirection: 'row'})
                    }
                /> 
            )
        } else {            
            return <ProjectItem {...ProjectItemMap[itemIndex]}/>
        }
        
    }

    function loadNextProjectInfo(e: SyntheticEvent) {
        if ((0 <= itemIndex) && (itemIndex < (ProjectItemMap.length - 1))) {
            itemIndex++
        } else if (itemIndex === (ProjectItemMap.length - 1)) {
            itemIndex = 0
        } else {
            console.error("loadNextProjectInfo")
            return null
        }
        setProjectItemLoaded(getProjectItem())        
    }

    function loadPrevProjectInfo(e: SyntheticEvent) {
        if ((0 < itemIndex) && (itemIndex <= (ProjectItemMap.length - 1))) {
            itemIndex --
        } else if (itemIndex === 0) {
            itemIndex = (ProjectItemMap.length - 1)
        } else {
            console.error("loadPrevProjectInfo", itemIndex)
            return null
        }
        setProjectItemLoaded(getProjectItem())        
    }

    return (
    <Paper>
        <Box className='projectSection' id='projectSection' sx={{ 
            height: "100vh", 
            maxHeight: "100vh", 
            width:"100%", 
            maxWidth:"100%", 
            display: 'flex', 
            justifyContent: 'center', 
            pt: "64px", 
            alignItems: "center"            
        }}>
            {isMobile? (
                <Box sx={{ 
                    height: "100%", 
                    maxHeight: "100%", 
                    width:"100%", 
                    maxWidth:"100%", 
                    m: 1,                    
                    display: 'flex', 
                    flexDirection: 'column',
                    justifyContent: 'space-between',                     
                    alignItems: "center"            
                }}>
                    {ProjectItemLoaded}         
                    <Stack direction="row" spacing={4} sx={{alignItems: 'center', justifyItems: 'center', mb: 4}}>
                        <IconButton onClick={loadPrevProjectInfo} color="secondary" sx={{width: '56px', height: '56px', p: 0, m: 0}}>
                            <Avatar src={left_arrow} alt="O" sx={{width: '32px', height: '32px', p: 0, m: 0}} />
                        </IconButton>                       
                        <IconButton onClick={loadNextProjectInfo} color="secondary" sx={{width: '56px', height: '56px', p: 0, m: 0}}>
                            <Avatar src={right_arrow} alt="O" sx={{width: '32px', height: '32px', p: 0, m: 0}} />
                        </IconButton>
                    </Stack>  
                </Box>
            ):(
                <Stack direction="row" spacing={4} sx={{alignItems: 'center'}}>
                    <IconButton onClick={loadPrevProjectInfo} color="secondary" sx={{width: '56px', height: '56px', p: 0, m: 0}}>
                        <Avatar src={left_arrow} alt="O" sx={{width: '32px', height: '32px', p: 0, m: 0}} />
                    </IconButton>   
                    {ProjectItemLoaded}         
                    <IconButton onClick={loadNextProjectInfo} color="secondary" sx={{width: '56px', height: '56px', p: 0, m: 0}}>
                        <Avatar src={right_arrow} alt="O" sx={{width: '32px', height: '32px', p: 0, m: 0}} />
                    </IconButton>
                </Stack>  
            )}
        </Box>
    </Paper>
    )
}