import { Box, Button, Paper, Stack, TextField, Typography, useMediaQuery, useTheme } from '@mui/material';
import { ResponsiveStyleValue} from '@mui/system';
import * as React from 'react';

import gmaillogo from "../../assets/google-gmail.svg";
import linkedinlogo from "../../assets/linkedin-icon.svg";
import twitterlogo from "../../assets/twitter.svg";
import instalogo from "../../assets/instagram-icon.svg";
import gitlogo from "../../assets/github-octocat.svg";
// END REGION


export interface IEmailMeProps {}
export function EmailMe (props: IEmailMeProps) {
    const theme = useTheme()
    const isMobile = useMediaQuery(theme.breakpoints.down('md'))     
    const [itemWidth, setItemWidth] = React.useState("50%")    
    
    React.useEffect(() => {
        if (isMobile) {
            setItemWidth("100%")
        } else {
            setItemWidth("50%")
        }
    })

    function sendMessage() {        
        const name: string = (document.getElementById("name-field") as HTMLInputElement).value
        const email: string = (document.getElementById("email-field") as HTMLInputElement).value
        const message: string = (document.getElementById("message-field") as HTMLInputElement).value
        if ((name === "") || (email === "") || (message === "")) {
            return null
        }
        console.log(`${name}\n${email}\n${message}`)
    }

    return (
        <Box sx={{p: 1, m: 0, width: itemWidth, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyItems: 'center'}}>   
            {isMobile? (
                <Box
                    sx={{'& .MuiTextField-root': {mt: 1, mb: 1, ml: 0, mr: 0}, p: 1, m: 0, width: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyItems: 'center'}}
                    component="form"
                    noValidate
                    autoComplete="off"            
                >                       
                    <TextField size="small" fullWidth={true} focused color="secondary" required id="name-field" label="Name" placeholder="Enter Name"/>
                    <TextField size="small" fullWidth={true} focused color="secondary" required id="email-field" label="Email" placeholder="Enter Email ID"/>
                    <TextField size="small" fullWidth={true} focused color="secondary" multiline rows={4} required id="message-field" label="Message" placeholder="Enter Your Message"/>
                </Box>
            ):(
                <Box
                    sx={{'& .MuiTextField-root': {mt: 1, mb: 1, ml: 0, mr: 0}, p: 2, m: 0, width: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyItems: 'center'}}
                    component="form"
                    noValidate
                    autoComplete="off"            
                >                       
                    <TextField size="small" fullWidth={true} focused color="secondary" required id="name-field" label="Name" placeholder="Enter Name"/>
                    <TextField size="small" fullWidth={true} focused color="secondary" required id="email-field" label="Email" placeholder="Enter Email ID"/>
                    <TextField size="small" fullWidth={true} focused color="secondary" multiline rows={12} required id="message-field" label="Message" placeholder="Enter Your Message"/>
                </Box>
            )}
            <Button sx={{mt: 2}} variant="outlined" size="large" color="secondary" onClick={sendMessage}>Send</Button>
        </Box>           
    );
}


export interface IContactLinksProps {}
export function ContactLinks (props: IContactLinksProps) {
    interface ISocialLinksProps {
        image: any;
        name: string;
        social_link: string;
    }

    const theme = useTheme()
    const isMobile = useMediaQuery(theme.breakpoints.down('md')) 
    const ContactsItemJSON: ISocialLinksProps[] = [
        {social_link:"https://www.linkedin.com/in/ommar-shaikh-0a4a21229/", image:linkedinlogo, name:'LINKEDIN'},
        {social_link:"mailto:ommarshaikh20@gmail.com", image:gmaillogo, name:'GMAIL'},
        {social_link:"https://github.com/OmmarShaikh01", image:gitlogo, name:'GITHUB'},
        {social_link:"https://twitter.com/ommarshaikh20", image:twitterlogo, name:'TWITTER'},
        {social_link:"https://www.instagram.com/ommarshaikh20/", image:instalogo, name:'INSTAGRAM'},
    ]
    const [width, setWidth] = React.useState('100%')
    const [direction, setDirection] = React.useState<ResponsiveStyleValue<'row' | 'row-reverse' | 'column' | 'column-reverse'>>('column')    

    React.useEffect(() => {
        if (isMobile){
            setWidth('100%')
            setDirection('row')
        } else {
            setWidth('50%')
            setDirection('column')            
        } 
    })

    function ContactItem(props: ISocialLinksProps) {    
        var size = ""        
        var variant = "" as "body2" | "h6"

        if (isMobile){
            size = "32px"        
            variant = "body2"        
        } else {
            size = "96px"        
            variant = "h6"        
        }         

        return (
        <Box sx={{display: "flex", flexDirection: 'column', alignItems: 'center'}}>
            <a target="_blank" rel="noreferrer noopener" href={props.social_link}>
                <img width={size} height={size} src={props.image} alt=""/>
            </a>
            <Typography sx={{fontWeight: "bold", color: "text.primary", m:1}} align="center" variant={variant} id={props.name}>{props.name}</Typography>
        </Box>
        )
    }

    return (
    <Box sx={{width: width, p: 2, pt: 4, m: 0, display: "grid", rowGap: "8%", columnGap: '4%', gridTemplateColumns: "repeat(3, 1fr)"}}>
        {ContactsItemJSON.map((link) => <ContactItem key={link.name} social_link={link.social_link} image={link.image} name={link.name} />)}
    </Box>        
  );
}


export interface IContactsProps {}
export default function Contacts (props: IContactsProps) {
    const theme = useTheme()
    const isMobile = useMediaQuery(theme.breakpoints.down('md')) 

    return (
    <Paper>
        <Box className='contactsSection' id='contactsSection' sx={{width: 'inherit', height: '100vh', pt: '64px'}}>            
            {!isMobile? (
                <div>
                    <Typography variant="h3" sx={{pb: 0, pl: 1, fontWeight: "bold", color: 'text.primary'}}>Contact Me</Typography>                    
                    <Box sx={{width: "100%", display: 'flex', flexDirection: 'row', alignItems: 'flex-start', justifyItems: 'center'}}>                
                        <EmailMe/>
                        <ContactLinks/>
                    </Box>        
                </div>
            ): (
                <Box sx={{pt: 1, height: "100%", width: "100%", display: 'flex', flexDirection: 'column', alignItems: 'flex-start', justifyItems: 'center'}}>
                    <Typography variant="h4" sx={{pb: 0, pl: 1, fontWeight: "bold", color: 'text.primary'}}>Contact Me</Typography>
                    <ContactLinks/>
                    <hr style={{width: "90%", border: '1px solid black', textAlign: "center", marginLeft: 'auto', marginRight: 'auto', marginTop: '4px'}}/>
                    <EmailMe/>
                </Box>  
            )}
        </Box>
    </Paper>        
    );
}
