import {Box, Skeleton, Button, Container, Paper, Stack, Typography, useMediaQuery, useTheme}  from '@mui/material'
import { Link } from 'react-scroll'
import React from 'react'

import logo  from "../../assets/placeholder.png";
import './Research.css'


function ResearchViewSkeleton() {
    return (
    <Paper variant="outlined" sx={{borderRadius: "8px", p:2, alignContent: 'center', justifyContent: 'center'}}>
        <Box sx={{maxWidth:"fit-content"}}>
            <Stack id="researchContent" direction="column" spacing={1}>
                <a id="researchImage" href="#researchSegment">
                    <Skeleton animation={'wave'} variant="rectangular" width={256} height={256} sx={{borderRadius: "10px"}}/>
                </a>
                <Typography sx={{fontWeight: "bold", color: "text.primary", m:0}} align="left" variant="h6">
                    <Skeleton animation={'wave'} variant="text" width={224} sx={{p: 1, borderRadius: "8px"}}> Pending Update</Skeleton>
                </Typography>
                <Typography
                    sx={{color: "text.primary", textAlign:"justify"}}
                    paragraph={true}
                    align="center"
                    variant="subtitle2">
                    <Skeleton animation={'wave'} variant="rectangular" width={256} height={200} sx={{borderRadius: "10px"}}/>
                </Typography>
            </Stack>
        </Box>
    </Paper>
    )
}


type ResearchProps = {}
export default function Research({}: ResearchProps) {    
 
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down("md"));
    return (
        <Paper>
            <Box className='researchSection' id='researchSection' sx={{
                height: "100vh", 
                maxHeight: "100vh", 
                width: '100%',
                maxWidth: '100%',
                m: 0,
                p: 2,                          
                pt: '64px',           
                display: 'flex',
                justifyContent: 'center',
                alignItems: "center"
            }}>                         
                <Box sx={{            
                    display: 'flex',
                    justifyContent: 'center',
                    alignItems: "center",
                    pt: 2                    
                }}>
                    <div className="scroll">
                        <Stack direction="row" spacing={6}>
                            <ResearchViewSkeleton/>
                            <ResearchViewSkeleton/>
                            <ResearchViewSkeleton/>
                            <ResearchViewSkeleton/>
                        </Stack>
                    </div>
                </Box> 
            </Box>
        </Paper>
    )
}