import React from 'react';
import { AppBar, Avatar, Button, IconButton, Menu, MenuItem, MenuList, Paper, Stack, Toolbar, Typography, Slide, useMediaQuery, useTheme, useScrollTrigger } from "@mui/material";
import { Box } from '@mui/system';
import MenuIcon from '@mui/icons-material/Menu';
import MenuOpenIcon from '@mui/icons-material/MenuOpen';
import { Link } from 'react-scroll'
// END REGION


interface INavbarAvatarProps {
    title: string;
    subtitle: string;
    avatar: string;
}

function NavbarAvatar (props: INavbarAvatarProps) {
    return (    
    <Box sx={{display: 'flex', flexDirection:'row', height: "64px", maxHeight: "64px", alignItems: 'center', pl: 1}}>
        <Avatar src={props.avatar} alt="" sx={{height: "48px", maxHeight: "48px", width: "48px", maxWidth: "48px", border: "2px solid", borderColor: 'secondary.main'}}/>
        <Box sx={{display: 'flex', flexDirection:'column', pl: 1}}>      
            <Link spy={true} smooth={true} duration={400} to="#" >
                <Typography variant="body1" sx={{pl:'4px', fontWeight: "900", color: 'secondary.main'}}>{props.title}</Typography>    
            </Link>                      
            <Link spy={true} smooth={true} duration={400} to="#" >
                <Typography variant="caption" sx={{pl:'4px', fontWeight: "400", color: 'text.primary'}}>{props.subtitle}</Typography>
            </Link>                      
        </Box>
    </Box>
    );
}


function NavBarMenu () {
    const theme = useTheme()
    const isMobile = useMediaQuery(theme.breakpoints.down('md'))

    const [menuExpanded, setmenuExpanded] = React.useState(false);
    const [menuAnchorEl, setmenuAnchorEl] = React.useState<null | HTMLElement>(null);
    
    const expandMenu = (event: React.MouseEvent<HTMLButtonElement>) => {
        if(menuExpanded)  {
            setmenuAnchorEl(null)
            setmenuExpanded(false)
        } else {
            setmenuAnchorEl(event.currentTarget)
            setmenuExpanded(true)
        }
    }

    const menuItems: string[][] = [
        ["Home", "homeSection"], ["About", "aboutSection"],
        ["Projects", "projectSection"],["Research", "researchSection"],
        ["Contacts", "contactsSection"]
    ]

    function LinkItem(title: string, link: string) {
        return (
            <Link spy={true} smooth={true} duration={400} to={link}>
                <Typography variant="caption" sx={{pl:'4px', fontWeight: "bold", color: 'text.primary'}}>{title}</Typography>
            </Link> 
        )
    }

    return (
        <div> 
            {isMobile? (
                <div>
                    <IconButton color={'secondary'} sx={{p: 2, m: 0, width: '64px', height: '64px'}} onClick={expandMenu}>
                        {menuExpanded ? (
                            <MenuOpenIcon/>
                        ):(
                            <MenuIcon/>
                        )}                                        
                    </IconButton>
                    <Menu open={menuExpanded} onClose={expandMenu} anchorEl={menuAnchorEl}>                    
                        <MenuList>
                            {menuItems.map((link: string[]) => <MenuItem key={link[0]}>{LinkItem(link[0], link[1])}</MenuItem>)}    
                        </MenuList>
                    </Menu>
                </div>
            ):(
                <Stack direction='row' spacing={2}>
                    {menuItems.map((link: string[]) => <Button size="large" color="secondary" key={link[0]}>{LinkItem(link[0], link[1])}</Button>)}
                </Stack>
            )}            
        </div>
    );
}


export default function Navbar () {
    const [nav, setnav] = React.useState('-64px')
    const changeBackground = () => {        
        setnav(!(window.scrollY >= window.innerHeight * 0.5) ? ('-64px'): ('0px'))
        
    }
    window.addEventListener('scroll', changeBackground)

    return (        
    <AppBar position="fixed" sx={{p: 0, m: 0, height: "64px", maxHeight: "64px", top: nav, left: 0, transition: "ease-in-out 0.6s"}}>
        <Paper>
            <Toolbar sx={{p: 0, m: 0, display: 'flex', justifyContent: 'space-between'}} disableGutters>
                <NavbarAvatar title='Ommar Shaikh' subtitle='Fullstack Developer' avatar=''/>                    
                <NavBarMenu/>
            </Toolbar>
        </Paper>
    </AppBar>
    );
}
